.room-footer {
  border-top: 1px solid var(--border);
  background: var(--surface);
  padding: 14px 20px 18px;
  flex-shrink: 0;
}

.locked-footer {
  text-align: center;
  color: var(--text-muted);
  font-size: 14px;
  font-weight: 500;
  padding: 16px;
}

.contribution-form {
  max-width: 800px;
  margin: 0 auto;
  background: var(--bg);
  border: 1.5px solid var(--border);
  border-radius: 18px;
  transition: border-color .2s, box-shadow .2s;
  overflow: hidden;
}
.contribution-form:focus-within {
  border-color: var(--primary);
  box-shadow: 0 0 0 4px rgba(99,102,241,.12);
}

.contribution-input {
  width: 100%;
  padding: 14px 16px 6px;
  border: none;
  font-size: 15px;
  font-family: var(--font);
  background: transparent;
  color: var(--text);
  resize: none;
  outline: none;
  line-height: 1.6;
  box-sizing: border-box;
  display: block;
}
.contribution-input::placeholder { color: var(--text-muted); }

.form-actions {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 4px 10px 10px;
}
.form-hint { font-size: 12px; color: var(--text-muted); font-weight: 500; padding-left: 4px; }

/* ===================== CHAT VIEW ===================== */

.chat-view {
  max-width: 800px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;

