            {editError && <p className="edit-error">{editError}</p>}
            <div className="edit-actions">
              <button className="btn btn-secondary" onClick={handleEditCancel} disabled={editSaving}>
                Cancel
              </button>
              <button className="btn btn-primary" onClick={handleEditSave} disabled={editSaving || !editText.trim()}>
                {editSaving ? 'Saving…' : 'Save'}
              </button>
            </div>
          </div>
        ) : (
          <p>{contribution.content}</p>
        )}
      </div>

      {/* Footer: reactions + comment toggle */}
      <div className="contribution-footer">
        <div className="reactions-row">
          {Object.entries(reactionGroups).map(([emoji, { count, hasMe }]) => (
            <button
              key={emoji}
              className={`reaction-chip ${hasMe ? 'reaction-chip--active' : ''}`}
              onClick={() => onReact(contribution.id, emoji)}
            >
              {emoji} {count}
            </button>
          ))}
          <div className="reaction-picker-wrap" ref={pickerRef}>
            <button
              className="add-reaction-btn"
              onClick={() => setShowPicker(v => !v)}
              title="Add reaction"
            >
              + 😊
            </button>
            {showPicker && (
              <div className="reaction-picker">
                {REACTIONS.map(emoji => (
                  <button
                    key={emoji}
                    className="reaction-option"
                    onClick={() => { onReact(contribution.id, emoji); setShowPicker(false); }}
                  >
                    {emoji}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>

        <button className="comment-toggle" onClick={handleToggleComments}>
          💬 {hasCommentData ? commentCount : '…'} comment{commentCount !== 1 ? 's' : ''}
        </button>
      </div>

      {/* Comments */}
      {showComments && (
        <CommentSection
          contributionId={contribution.id}
          comments={contribution.comments || []}
          currentUser={currentUser}
          onAddComment={onAddComment}
        />
      )}
    </article>
  );
}

export default ContributionItem;

import React from 'react';
import { getAuthorColor } from '../utils';

function DocumentView({ contributions, roomTitle }) {
  if (contributions.length === 0) {
    return (
      <div className="empty-state">
        <div className="empty-icon">📄</div>
        <p>No content yet.</p>
        <p className="empty-sub">Switch to Chat view to start writing.</p>
      </div>
    );
  }

  const authors = [...new Set(contributions.map(c => c.author_name))];

  return (
    <div className="document-view">
      {roomTitle && <h1 className="document-title">{roomTitle}</h1>}

      <div className="document-byline">
        {authors.map((name, i) => (
          <span key={name} className="document-author" style={{ color: getAuthorColor(contributions.find(c => c.author_name === name)?.author_id) }}>
            {name}{i < authors.length - 1 ? ', ' : ''}
          </span>
        ))}
      </div>

      <div className="document-body">
        {contributions.map((c, i) => (
          <p key={c.id} className="document-paragraph">
            {c.content}
          </p>
        ))}
      </div>

      <div className="document-meta">
        {contributions.length} contribution{contributions.length !== 1 ? 's' : ''} by {authors.length} author{authors.length !== 1 ? 's' : ''}
      </div>
    </div>
  );
}

export default DocumentView;

