/* ===================== RESET & VARIABLES ===================== */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg: #f6f8fc;
  --surface: #ffffff;
  --surface-raised: #ffffff;
  --border: #dde3ed;
  --border-focus: #6366f1;
  --primary: #6366f1;
  --primary-hover: #4f46e5;
  --primary-light: #eef2ff;
  --secondary-bg: #eef1f7;
  --secondary-hover: #dde3ed;
  --text: #111827;
  --text-muted: #6b7280;
  --danger: #ef4444;
  --warning: #f59e0b;
  --success: #10b981;
  --radius: 10px;
  --radius-lg: 16px;
  --shadow: 0 1px 2px rgba(0,0,0,.04), 0 4px 16px rgba(0,0,0,.06);
  --shadow-md: 0 4px 24px rgba(0,0,0,.1), 0 1px 4px rgba(0,0,0,.06);
  --font: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
}

[data-theme="dark"] {
  --bg: #0b1120;
  --surface: #131c2e;
  --surface-raised: #1a2540;
  --border: #1d2d44;
  --border-focus: #818cf8;
  --primary: #818cf8;
  --primary-hover: #6366f1;
  --primary-light: #1e1b4b;
  --secondary-bg: #1a2540;
  --secondary-hover: #1f2f4a;
  --text: #eef2ff;
  --text-muted: #8896b0;
  --shadow: 0 1px 2px rgba(0,0,0,.3), 0 4px 16px rgba(0,0,0,.4);
  --shadow-md: 0 8px 32px rgba(0,0,0,.5), 0 1px 4px rgba(0,0,0,.3);
}

[data-theme="dark"] .notif-item--unread { background: #1e1b4b; }
[data-theme="dark"] .badge-locked { background: #451a03; color: #fcd34d; }
[data-theme="dark"] .delete-btn:hover { background: #450a0a; color: var(--danger); }
[data-theme="dark"] .edit-btn:hover { background: #1e1b4b; color: var(--primary); }
[data-theme="dark"] .comment { background: #0b1120; }
[data-theme="dark"] .home-container { background: radial-gradient(ellipse at 60% 0%, rgba(99,102,241,.12) 0%, transparent 60%); }

body {
  font-family: var(--font);
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
  font-size: 15px;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  transition: background .2s, color .2s;
}

/* ===================== UTILITIES ===================== */

.loading-screen {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100vh;
  background: var(--bg);
}

.spinner {
  width: 32px;
  height: 32px;
  border: 2.5px solid var(--border);
  border-top-color: var(--primary);
  border-radius: 50%;
  animation: spin .7s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

.error-screen {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100vh;
  gap: 16px;
  color: var(--text-muted);
  text-align: center;
  padding: 24px;
}
.error-screen h2 { color: var(--text); font-size: 22px; font-weight: 700; }

/* ===================== BUTTONS ===================== */

.btn {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 8px 16px;
  border-radius: var(--radius);
  border: none;
  cursor: pointer;
  font-size: 14px;
  font-weight: 600;
  line-height: 1;
  letter-spacing: -0.01em;
  transition: background .15s, box-shadow .15s, transform .1s;
  white-space: nowrap;
  font-family: var(--font);
}
.btn:disabled { opacity: .45; cursor: not-allowed; }
.btn:active:not(:disabled) { transform: scale(.98); }

.btn-primary { background: var(--primary); color: #fff; box-shadow: 0 1px 3px rgba(99,102,241,.3); }
.btn-primary:hover:not(:disabled) { background: var(--primary-hover); box-shadow: 0 2px 8px rgba(99,102,241,.4); }

.btn-secondary { background: var(--secondary-bg); color: var(--text); border: 1px solid var(--border); }
.btn-secondary:hover:not(:disabled) { background: var(--secondary-hover); }

.btn-warning { background: var(--warning); color: #fff; }
.btn-warning:hover:not(:disabled) { filter: brightness(.92); }

.btn-success { background: var(--success); color: #fff; }
.btn-success:hover:not(:disabled) { filter: brightness(.92); }

.btn-sm {
  padding: 5px 12px;
  font-size: 13px;
  font-weight: 600;
  border-radius: var(--radius);
  border: none;
  cursor: pointer;
  background: var(--primary);
  color: #fff;
  font-family: var(--font);
}
.btn-sm:disabled { opacity: .45; cursor: not-allowed; }

.btn-link {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 13px;
  font-weight: 500;
  text-decoration: none;
  padding: 4px 8px;
  border-radius: 6px;
  font-family: var(--font);
  transition: color .15s, background .15s;
}
.btn-link:hover { color: var(--text); background: var(--secondary-bg); }
.btn-link.muted { color: var(--text-muted); }

.btn-icon {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 18px;
  color: var(--text-muted);
  padding: 6px 8px;
  border-radius: var(--radius);
  line-height: 1;
  transition: background .15s, color .15s;
}
.btn-icon:hover { background: var(--secondary-bg); color: var(--text); }

/* ===================== INPUTS ===================== */

.input {
  width: 100%;
  padding: 10px 14px;
  border: 1.5px solid var(--border);
  border-radius: var(--radius);
  font-size: 15px;
  font-family: var(--font);
  font-weight: 400;
  background: var(--surface);
  color: var(--text);
  outline: none;
  transition: border-color .15s, box-shadow .15s;
}
.input::placeholder { color: var(--text-muted); }
.input:focus {
  border-color: var(--border-focus);
  box-shadow: 0 0 0 3px rgba(99,102,241,.12);
}
.input--sm {
  padding: 6px 10px;
  font-size: 13px;
}

/* ===================== BADGES ===================== */

.badge {
  display: inline-flex;
  align-items: center;
  padding: 3px 10px;
  border-radius: 99px;
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.01em;
}
.badge-locked { background: #fef3c7; color: #92400e; }

/* ===================== THEME TOGGLE ===================== */

.theme-toggle {
  position: fixed;
  top: 16px;
  right: 16px;
  background: var(--surface);
  border: 1.5px solid var(--border);
  border-radius: var(--radius);
  padding: 7px 11px;
  font-size: 17px;
  cursor: pointer;
  box-shadow: var(--shadow);
  z-index: 100;
  transition: background .15s, box-shadow .15s;
}
.theme-toggle:hover { background: var(--secondary-bg); box-shadow: var(--shadow-md); }

/* ===================== HOME ===================== */

.home-container {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 32px 24px;
  background: radial-gradient(ellipse at 50% 0%, rgba(99,102,241,.08) 0%, transparent 55%);
}

.home-hero {
  text-align: center;
  max-width: 640px;
  width: 100%;
}

.home-logo {
  width: 76px;
  height: 76px;
  border-radius: 22px;
  background: linear-gradient(140deg, #6366f1 0%, #a855f7 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 36px;
  font-weight: 900;
  color: #fff;
  margin: 0 auto 20px;
  letter-spacing: 0;
  box-shadow: 0 8px 32px rgba(99,102,241,.4), 0 2px 8px rgba(99,102,241,.2);
  font-family: 'Orbitron', sans-serif;
  user-select: none;
}

.home-title {
  font-size: 48px;
  font-weight: 700;
  color: var(--primary);
  letter-spacing: 2px;
  margin-bottom: 10px;
  line-height: 1.1;
  font-family: 'Orbitron', sans-serif;
}

.home-subtitle {
  font-size: 17px;
  color: var(--text-muted);
  margin-bottom: 40px;
  font-weight: 400;
}

.name-form {
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-width: 420px;
  margin: 0 auto 16px;
}

.color-picker-row {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 16px;
}

.color-picker-label {
  font-size: 13px;
  color: var(--text-muted);
  white-space: nowrap;
  font-weight: 500;
}

.color-picker {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.color-swatch {
  width: 20px;
  height: 20px;
  border-radius: 50%;
  border: 2px solid transparent;
  cursor: pointer;
  transition: transform .15s, box-shadow .15s;
  outline: none;
  padding: 0;
  flex-shrink: 0;
}
.color-swatch:hover { transform: scale(1.2); }
.color-swatch--active {
  border-color: #fff;
  box-shadow: 0 0 0 2px rgba(0,0,0,0.35);
  transform: scale(1.15);
}
[data-theme="dark"] .color-swatch--active {
  box-shadow: 0 0 0 2.5px rgba(255,255,255,0.5);
}

.error-text {
  color: var(--danger);
  font-size: 14px;
  margin-top: 10px;
  font-weight: 500;
}

.home-actions {
  display: grid;
  grid-template-columns: 1fr;
  gap: 0;
  align-items: start;
  text-align: left;
  margin-bottom: 28px;
  max-width: 675px;
  margin-left: auto;
  margin-right: auto;
}

.action-card {
  background: var(--surface);
  border: 1.5px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 24px;
  box-shadow: var(--shadow);
  transition: box-shadow .2s;
}
.action-card:hover { box-shadow: var(--shadow-md); }
.action-card h2 {
  font-size: 16px;
  font-weight: 700;
  letter-spacing: -0.02em;
  margin-bottom: 6px;
}
.action-desc {
  font-size: 13px;
  color: var(--text-muted);
  margin-bottom: 16px;
  line-height: 1.55;
}
.action-card form {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.home-divider {
  display: flex;
  align-items: center;
  justify-content: center;
  padding-top: 48px;
  color: var(--text-muted);
  font-size: 13px;
  font-weight: 500;
}

/* ===================== ROOM LAYOUT ===================== */

.room-layout {
  display: flex;
  flex-direction: column;
  height: 100vh;
  overflow: hidden;
}

.room-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 20px;
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  gap: 12px;
  flex-shrink: 0;
  min-height: 62px;
  backdrop-filter: blur(12px);
}

.room-header-left {
  display: flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
  flex: 1;
}

.room-header-right {
  display: flex;
  align-items: center;
  gap: 6px;
  flex-shrink: 0;
}

.room-title-wrap {
  display: flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
}

.room-title {
  font-size: 16px;
  font-weight: 700;
  letter-spacing: -0.02em;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 280px;
}

.view-toggle {
  display: flex;
  border: 1.5px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
  background: var(--secondary-bg);
}
.toggle-btn {
  padding: 6px 14px;
  border: none;
  background: transparent;
  cursor: pointer;
  font-size: 13px;
  font-weight: 600;
  color: var(--text-muted);
  transition: all .15s;
  font-family: var(--font);
  letter-spacing: -0.01em;
}
.toggle-btn.active {
  background: var(--primary);
  color: #fff;
  border-radius: calc(var(--radius) - 2px);
}
.toggle-btn:not(.active):hover { background: var(--secondary-hover); color: var(--text); }

.room-body {
  display: flex;
  flex: 1;
  overflow: hidden;
}

.room-main {
  flex: 1;
  overflow-y: auto;
  padding: 24px 20px;
  background: var(--bg);
  min-width: 0;
}

/* ===================== CHAT SIDEBAR ===================== */

.chat-sidebar {
  width: 300px;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  border-left: 1px solid var(--border);
  background: var(--surface);
  transition: width .25s ease;
  overflow: hidden;
}

.chat-sidebar--collapsed {
  width: 40px;
}

.chat-sidebar-header {
  padding: 10px 12px;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-muted);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  white-space: nowrap;
}

.chat-toggle-btn {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 16px;
  color: var(--text-muted);
  padding: 2px 6px;
  border-radius: 6px;
  line-height: 1;
  flex-shrink: 0;
  transition: background .15s, color .15s;
  font-family: var(--font);
}
.chat-toggle-btn:hover {
  background: var(--secondary-bg);
  color: var(--text);
}

.chat-sidebar--collapsed .chat-sidebar-header {
  justify-content: center;
  padding: 10px 0;
}

.chat-sidebar--collapsed .chat-toggle-btn {
  font-size: 18px;
}

.chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 10px 12px;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.chat-empty {
  font-size: 13px;
  color: var(--text-muted);
  text-align: center;
  padding: 24px 0;
  font-style: italic;
}

.chat-message {
  display: flex;
  gap: 8px;
  align-items: flex-start;
}

.chat-message--own .chat-message-content {
  background: var(--primary-light);
}

.chat-message-avatar {
  width: 26px;
  height: 26px;
  border-radius: 50%;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  font-weight: 700;
  color: #fff;
  margin-top: 1px;
}

.chat-message-body {
  flex: 1;
  min-width: 0;
}

.chat-message-meta {
  display: flex;
  align-items: baseline;
  gap: 5px;
  margin-bottom: 2px;
}

.chat-message-author {
  font-size: 12px;
  font-weight: 700;
}

.chat-message-time {
  font-size: 10px;
  color: var(--text-muted);
}

.chat-message-content {
  font-size: 13px;
  line-height: 1.5;
  word-break: break-word;
  background: var(--surface-raised);
  padding: 6px 10px;
  border-radius: 0 8px 8px 8px;
  color: var(--text);
}

.chat-input-form {
  display: flex;
  gap: 6px;
  padding: 10px 12px;
  border-top: 1px solid var(--border);
  flex-shrink: 0;
}

.chat-input {
  flex: 1;
  padding: 8px 10px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  background: var(--bg);
  color: var(--text);
  font-family: var(--font);
  font-size: 13px;
  outline: none;
  transition: border-color .15s;
  min-width: 0;
}
.chat-input:focus { border-color: var(--border-focus); }

.chat-send-btn {
  padding: 8px 12px;
  font-size: 16px;
  flex-shrink: 0;
}

/* ===================== TYPING BAR ===================== */

.typing-bar {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 5px 16px;
  font-size: 12px;
  font-weight: 500;
  color: var(--text-muted);
  font-style: italic;
  background: var(--surface);
  border-top: 1px solid var(--border);
  flex-shrink: 0;
}

.typing-dots {
  display: flex;
  gap: 3px;
}
.typing-dots span {
  width: 5px; height: 5px;
  border-radius: 50%;
  background: var(--primary);
  animation: bounce .9s ease infinite;
}
.typing-dots span:nth-child(2) { animation-delay: .15s; }
.typing-dots span:nth-child(3) { animation-delay: .3s; }
@keyframes bounce {
  0%, 80%, 100% { transform: translateY(0); }
  40% { transform: translateY(-5px); }
}

/* ===================== ROOM FOOTER ===================== */

.room-footer {
  border-top: 1px solid var(--border);
  background: var(--surface);
  padding: 14px 20px 18px;
  flex-shrink: 0;
}

.locked-footer {
  text-align: center;
  color: var(--text-muted);
  font-size: 14px;
  font-weight: 500;
  padding: 16px;
}

.contribution-form {
  max-width: 800px;
  margin: 0 auto;
  background: var(--bg);
  border: 1.5px solid var(--border);
  border-radius: 18px;
  transition: border-color .2s, box-shadow .2s;
  overflow: hidden;
}
.contribution-form:focus-within {
  border-color: var(--primary);
  box-shadow: 0 0 0 4px rgba(99,102,241,.12);
}

.contribution-input {
  width: 100%;
  padding: 14px 16px 6px;
  border: none;
  font-size: 15px;
  font-family: var(--font);
  background: transparent;
  color: var(--text);
  resize: none;
  outline: none;
  line-height: 1.6;
  box-sizing: border-box;
  display: block;
}
.contribution-input::placeholder { color: var(--text-muted); }

.form-actions {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 4px 10px 10px;
}
.form-hint { font-size: 12px; color: var(--text-muted); font-weight: 500; padding-left: 4px; }

/* ===================== CHAT VIEW ===================== */

.chat-view {
  max-width: 800px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

/* ===================== EMPTY STATE ===================== */

.empty-state {
  text-align: center;
  padding: 72px 24px;
  color: var(--text-muted);
}
.empty-icon { font-size: 40px; margin-bottom: 14px; }
.empty-state p { font-size: 16px; font-weight: 500; }
.empty-sub { font-size: 14px; margin-top: 6px; font-weight: 400; }

/* ===================== CONTRIBUTION ===================== */

.contribution {
  background: var(--surface);
  border: 1px solid var(--border);
  border-left: 4px solid var(--border);
  border-radius: 16px;
  padding: 16px 18px 16px 14px;
  transition: box-shadow .15s, transform .1s;
}
.contribution:hover { box-shadow: var(--shadow-md); transform: translateY(-1px); }
.contribution--own {
  border-color: rgba(99,102,241,.3);
  background: rgba(99,102,241,.04);
}

.contribution-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 10px;
}

.author-avatar {
  width: 30px;
  height: 30px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  font-weight: 700;
  color: #fff;
  flex-shrink: 0;
  letter-spacing: -0.5px;
}

.author-name {
  font-weight: 600;
  font-size: 14px;
  color: var(--text);
  letter-spacing: -0.01em;
}

.contribution-time {
  font-size: 12px;
  color: var(--text-muted);
  margin-left: auto;
  font-weight: 500;
}

.delete-btn {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 20px;
  line-height: 1;
  padding: 0 2px;
  margin-left: 4px;
  border-radius: 4px;
  transition: color .15s, background .15s;
}
.delete-btn:hover { color: var(--danger); background: #fee2e2; }

.edit-btn {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 15px;
  line-height: 1;
  padding: 2px 4px;
  margin-left: 4px;
  border-radius: 4px;
  transition: color .15s, background .15s;
}
.edit-btn:hover { color: var(--primary); background: var(--primary-light); }

.edited-label {
  font-size: 11px;
  color: var(--text-muted);
  font-style: italic;
  font-weight: 400;
}

.edit-form {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.edit-textarea {
  width: 100%;
  padding: 10px 12px;
  border: 1.5px solid var(--border-focus);
  border-radius: var(--radius);
  background: var(--bg);
  color: var(--text);
  font-family: var(--font);
  font-size: 15px;
  line-height: 1.75;
  resize: vertical;
  outline: none;
}

.edit-actions {
  display: flex;
  gap: 8px;
  justify-content: flex-end;
}

.edit-error {
  font-size: 13px;
  color: var(--danger);
}

.contribution-body p {
  line-height: 1.75;
  white-space: pre-wrap;
  word-break: break-word;
  font-size: 15px;
}

.contribution-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  margin-top: 12px;
  padding-top: 10px;
  border-top: 1px solid var(--border);
  flex-wrap: wrap;
}

/* ===================== REACTIONS ===================== */

.reactions-row {
  display: flex;
  align-items: center;
  gap: 5px;
  flex-wrap: wrap;
}

.reaction-chip {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 10px;
  border: 1.5px solid var(--border);
  border-radius: 99px;
  background: var(--secondary-bg);
  cursor: pointer;
  font-size: 13px;
  font-weight: 500;
  transition: all .15s;
  font-family: var(--font);
}
.reaction-chip:hover { border-color: var(--primary); background: var(--primary-light); }
.reaction-chip--active {
  background: var(--primary-light);
  border-color: var(--primary);
  color: var(--primary);
}

.reaction-picker-wrap { position: relative; }

.add-reaction-btn {
  padding: 3px 8px;
  border: 1.5px dashed var(--border);
  border-radius: 99px;
  background: transparent;
  cursor: pointer;
  font-size: 12px;
  font-weight: 500;
  color: var(--text-muted);
  transition: all .15s;
  font-family: var(--font);
}
.add-reaction-btn:hover { border-color: var(--primary); color: var(--primary); }

.reaction-picker {
  position: absolute;
  bottom: 34px;
  left: 0;
  background: var(--surface);
  border: 1.5px solid var(--border);
  border-radius: var(--radius);
  padding: 8px;
  display: flex;
  gap: 4px;
  box-shadow: var(--shadow-md);
  z-index: 200;
}
.reaction-option {
  font-size: 22px;
  padding: 4px 6px;
  border: none;
  background: none;
  cursor: pointer;
  border-radius: var(--radius);
  transition: background .1s, transform .1s;
}
.reaction-option:hover { background: var(--secondary-bg); transform: scale(1.15); }

.comment-toggle {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 13px;
  font-weight: 500;
  color: var(--text-muted);
  padding: 3px 8px;
  border-radius: var(--radius);
  transition: all .15s;
  font-family: var(--font);
}
.comment-toggle:hover { background: var(--secondary-bg); color: var(--text); }

/* ===================== COMMENTS ===================== */

.comment-section {
  margin-top: 14px;
  padding-top: 14px;
  border-top: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.comment-list { display: flex; flex-direction: column; gap: 6px; }

.comment {
  padding: 8px 12px;
  background: var(--bg);
  border-radius: var(--radius);
}

.comment-header {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 4px;
}

.comment-avatar {
  width: 22px; height: 22px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 10px;
  font-weight: 700;
  color: #fff;
  flex-shrink: 0;
}

.comment-author { font-weight: 600; font-size: 13px; letter-spacing: -0.01em; }
.comment-time { font-size: 11px; color: var(--text-muted); margin-left: auto; font-weight: 500; }
.comment-text { font-size: 14px; line-height: 1.55; white-space: pre-wrap; }

.reply-link {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 12px;
  font-weight: 500;
  text-decoration: underline;
  margin-top: 4px;
  padding: 0;
  font-family: var(--font);
}
.reply-link:hover { color: var(--primary); }

.reply-row, .add-comment-row {
  display: flex;
  gap: 8px;
  align-items: center;
  margin-top: 6px;
}

.no-comments { font-size: 13px; color: var(--text-muted); font-style: italic; font-weight: 400; }

/* ===================== DOCUMENT VIEW ===================== */

.document-view {
  max-width: 720px;
  margin: 0 auto;
  background: var(--surface);
  border: 1.5px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 56px 72px;
  box-shadow: var(--shadow);
  min-height: 400px;
}

.document-title {
  font-size: 34px;
  font-weight: 800;
  margin-bottom: 8px;
  line-height: 1.2;
  letter-spacing: -1px;
  color: var(--text);
}

.document-byline {
  font-size: 14px;
  color: var(--text-muted);
  margin-bottom: 36px;
  font-style: italic;
  font-weight: 400;
}

.document-body { }

.document-paragraph {
  font-size: 17px;
  line-height: 1.85;
  margin-bottom: 22px;
  white-space: pre-wrap;
  word-break: break-word;
}

.document-meta {
  margin-top: 48px;
  padding-top: 20px;
  border-top: 1px solid var(--border);
  font-size: 13px;
  color: var(--text-muted);
  font-weight: 500;
}

/* ===================== NOTIFICATIONS ===================== */

.notif-wrap { position: relative; }

.notif-bell {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 20px;
  padding: 6px 8px;
  border-radius: var(--radius);
  position: relative;
  transition: background .15s;
}
.notif-bell:hover { background: var(--secondary-bg); }

.notif-count {
  position: absolute;
  top: 2px; right: 2px;
  background: var(--danger);
  color: #fff;
  font-size: 10px;
  font-weight: 700;
  min-width: 16px; height: 16px;
  border-radius: 99px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0 3px;
  line-height: 1;
}

.notif-dropdown {
  position: absolute;
  right: 0; top: 44px;
  width: 316px;
  background: var(--surface);
  border: 1.5px solid var(--border);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-md);
  z-index: 500;
  overflow: hidden;
}

.notif-dropdown-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 14px;
  font-weight: 700;
  font-size: 14px;
  letter-spacing: -0.01em;
  border-bottom: 1px solid var(--border);
}

.notif-list { max-height: 320px; overflow-y: auto; }

.notif-item {
  display: flex;
  gap: 10px;
  align-items: flex-start;
  padding: 11px 14px;
  border-bottom: 1px solid var(--border);
  transition: background .1s;
}
.notif-item:last-child { border-bottom: none; }
.notif-item--unread { background: #f0f0ff; }

.notif-icon { font-size: 16px; flex-shrink: 0; margin-top: 1px; }
.notif-body { min-width: 0; }
.notif-message { font-size: 13px; line-height: 1.4; font-weight: 500; }
.notif-time { font-size: 11px; color: var(--text-muted); margin-top: 2px; display: block; font-weight: 400; }
.notif-empty { padding: 24px 14px; text-align: center; color: var(--text-muted); font-size: 14px; }

/* ===================== OVERLAY / PROMPT ===================== */

.overlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,.6);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  padding: 24px;
}

.prompt-card {
  background: var(--surface);
  border: 1.5px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 40px 32px;
  width: 100%;
  max-width: 400px;
  box-shadow: var(--shadow-md);
  text-align: center;
  display: flex;
  flex-direction: column;
  gap: 12px;
}
.prompt-icon { font-size: 40px; }
.prompt-card h2 { font-size: 20px; font-weight: 700; letter-spacing: -0.03em; }
.prompt-card p { font-size: 14px; color: var(--text-muted); }
.prompt-card form { display: flex; flex-direction: column; gap: 10px; }

/* ===================== CONTRIBUTION STATUS BADGES ===================== */

.contrib-status-badge {
  display: inline-flex;
  align-items: center;
  padding: 2px 8px;
  border-radius: 99px;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  flex-shrink: 0;
}
.contrib-status-badge--pending {
  background: #fef3c7;
  color: #92400e;
}
.contrib-status-badge--rejected {
  background: #fee2e2;
  color: #991b1b;
}
[data-theme="dark"] .contrib-status-badge--pending {
  background: #451a03;
  color: #fcd34d;
}
[data-theme="dark"] .contrib-status-badge--rejected {
  background: #450a0a;
  color: #fca5a5;
}

/* ===================== REVIEW VIEW ===================== */

.review-view {
  max-width: 820px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 32px;
  padding-bottom: 32px;
}

.review-section {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.review-section--collapsed {
  opacity: 0.7;
}

.review-section-header {
  display: flex;
  align-items: center;
  gap: 8px;
  padding-bottom: 10px;
  border-bottom: 2px solid var(--border);
}

.review-section-icon {
  font-size: 16px;
}

.review-section-title {
  font-size: 14px;
  font-weight: 700;
  letter-spacing: -0.01em;
  color: var(--text);
}

.review-count {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 22px;
  height: 22px;
  border-radius: 99px;
  font-size: 11px;
  font-weight: 700;
  padding: 0 6px;
}
.review-count--pending { background: #fef3c7; color: #92400e; }
.review-count--approved { background: #dcfce7; color: #166534; }
.review-count--rejected { background: #fee2e2; color: #991b1b; }

[data-theme="dark"] .review-count--pending { background: #451a03; color: #fcd34d; }
[data-theme="dark"] .review-count--approved { background: #052e16; color: #86efac; }
[data-theme="dark"] .review-count--rejected { background: #450a0a; color: #fca5a5; }

.review-section-hint {
  margin-left: auto;
  font-size: 12px;
  color: var(--text-muted);
  font-weight: 500;
}

.review-empty {
  font-size: 14px;
  color: var(--text-muted);
  font-style: italic;
  padding: 16px 0 4px;
}

.review-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

/* Base card */
.review-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 14px 16px;
  display: flex;
  gap: 12px;
  align-items: flex-start;
  transition: box-shadow .15s;
}
.review-card:hover { box-shadow: var(--shadow); }

/* Pending card: amber left border */
.review-card--pending {
  border-left: 4px solid #f59e0b;
}
.review-card--own {
  background: rgba(99,102,241,.04);
}

/* Approved card: green left border + position column */
.review-card--approved {
  border-left: 4px solid var(--success);
}

/* Rejected card: red left border, muted */
.review-card--rejected {
  border-left: 4px solid var(--danger);
  opacity: 0.75;
}

.review-card-position {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  flex-shrink: 0;
  width: 36px;
}

.review-pos-number {
  font-size: 11px;
  font-weight: 700;
  color: var(--text-muted);
  white-space: nowrap;
}

.review-movers {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.move-btn {
  background: none;
  border: 1px solid var(--border);
  border-radius: 4px;
  cursor: pointer;
  font-size: 10px;
  color: var(--text-muted);
  padding: 2px 5px;
  line-height: 1;
  transition: background .1s, color .1s, border-color .1s;
  font-family: var(--font);
}
.move-btn:hover:not(:disabled) {
  background: var(--primary-light);
  color: var(--primary);
  border-color: var(--primary);
}
.move-btn:disabled { opacity: 0.3; cursor: not-allowed; }

.review-card-body {
  flex: 1;
  min-width: 0;
}

.review-card-header {
  display: flex;
  align-items: center;
  gap: 7px;
  margin-bottom: 8px;
  flex-wrap: wrap;
}

.review-card-avatar {
  width: 26px;
  height: 26px;
  border-radius: 50%;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  font-weight: 700;
  color: #fff;
  flex-shrink: 0;
}

.review-card-author {
  font-size: 13px;
  font-weight: 700;
  letter-spacing: -0.01em;
}

.review-card-you {
  font-size: 10px;
  font-weight: 600;
  color: var(--text-muted);
  background: var(--secondary-bg);
  padding: 1px 6px;
  border-radius: 99px;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.review-card-time {
  font-size: 11px;
  color: var(--text-muted);
  margin-left: auto;
}

.review-card-content {
  font-size: 14px;
  line-height: 1.7;
  color: var(--text);
  white-space: pre-wrap;
  word-break: break-word;
}

.review-card-actions {
  display: flex;
  gap: 8px;
  margin-top: 12px;
  padding-top: 10px;
  border-top: 1px solid var(--border);
}

.btn-approve {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 5px 14px;
  border-radius: var(--radius);
  border: 1.5px solid #16a34a;
  background: transparent;
  color: #16a34a;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  font-family: var(--font);
  transition: background .15s, color .15s;
}
.btn-approve:hover {
  background: #dcfce7;
  color: #15803d;
}
[data-theme="dark"] .btn-approve {
  border-color: #4ade80;
  color: #4ade80;
}
[data-theme="dark"] .btn-approve:hover {
  background: #052e16;
  color: #86efac;
}

.btn-reject {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 5px 14px;
  border-radius: var(--radius);
  border: 1.5px solid var(--border);
  background: transparent;
  color: var(--text-muted);
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  font-family: var(--font);
  transition: background .15s, color .15s, border-color .15s;
}
.btn-reject:hover {
  border-color: var(--danger);
  color: var(--danger);
  background: #fee2e2;
}
[data-theme="dark"] .btn-reject:hover {
  background: #450a0a;
}

/* ===================== LOCK BUTTONS ===================== */

.lock-btn {
  background: var(--secondary-bg);
  color: var(--text-muted);
  border: 1.5px solid var(--border);
  font-size: 13px;
  padding: 6px 11px;
}
.lock-btn:hover:not(:disabled) {
  background: var(--secondary-hover);
  color: var(--text);
}
.lock-btn--active {
  background: #fef3c7;
  color: #92400e;
  border-color: #f59e0b;
}
.lock-btn--active:hover:not(:disabled) {
  background: #fde68a;
}
[data-theme="dark"] .lock-btn--active {
  background: #451a03;
  color: #fcd34d;
  border-color: #b45309;
}

.contributors-btn {
  font-size: 13px;
  padding: 6px 11px;
  font-weight: 600;
}

/* ===================== CONTRIBUTORS PANEL ===================== */

.contributors-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, .55);
  backdrop-filter: blur(4px);
  z-index: 600;
  display: flex;
  align-items: flex-start;
  justify-content: flex-end;
  padding: 62px 16px 16px;
}

.contributors-panel {
  width: 360px;
  max-height: calc(100vh - 80px);
  background: var(--surface);
  border: 1.5px solid var(--border);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-md);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  animation: slideInRight .2s ease;
}

@keyframes slideInRight {
  from { transform: translateX(20px); opacity: 0; }
  to   { transform: translateX(0);    opacity: 1; }
}

.contributors-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px 16px;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}

.contributors-title {
  display: flex;
  align-items: center;
  gap: 8px;
}

.contributors-icon { font-size: 18px; }

.contributors-title h2 {
  font-size: 15px;
  font-weight: 700;
  letter-spacing: -0.02em;
}

.contributors-count {
  background: var(--primary-light);
  color: var(--primary);
  font-size: 11px;
  font-weight: 700;
  padding: 2px 7px;
  border-radius: 99px;
}

.contributors-body {
  flex: 1;
  overflow-y: auto;
  padding: 12px 0;
}

.contributors-section {
  padding: 0 16px 16px;
}
.contributors-section + .contributors-section {
  border-top: 1px solid var(--border);
  padding-top: 16px;
}

.contributors-section-label {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-muted);
  margin-bottom: 10px;
}

.contributors-empty {
  font-size: 13px;
  color: var(--text-muted);
  font-style: italic;
}

.contributors-list {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.contributor-row {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 10px;
  border-radius: var(--radius);
  transition: background .1s;
}
.contributor-row:hover { background: var(--secondary-bg); }
.contributor-row--removed { opacity: 0.6; }

.contributor-avatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
  font-weight: 700;
  color: #fff;
}

.contributor-info {
  flex: 1;
  min-width: 0;
}

.contributor-name {
  font-size: 13px;
  font-weight: 600;
  letter-spacing: -0.01em;
  display: block;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.contributor-meta {
  font-size: 11px;
  color: var(--text-muted);
  display: block;
  margin-top: 1px;
}

.contributor-badges {
  display: flex;
  align-items: center;
  gap: 5px;
  flex-shrink: 0;
}

.contributor-badge {
  font-size: 10px;
  font-weight: 700;
  padding: 2px 7px;
  border-radius: 99px;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}
.contributor-badge--you { background: var(--primary-light); color: var(--primary); }
.contributor-badge--admin { background: #fef3c7; color: #92400e; }
.contributor-badge--removed { background: #fee2e2; color: #991b1b; }

[data-theme="dark"] .contributor-badge--admin { background: #451a03; color: #fcd34d; }
[data-theme="dark"] .contributor-badge--removed { background: #450a0a; color: #fca5a5; }

.contributor-remove-btn {
  background: none;
  border: 1.5px solid var(--border);
  border-radius: 6px;
  cursor: pointer;
  font-size: 11px;
  font-weight: 600;
  color: var(--text-muted);
  padding: 2px 9px;
  font-family: var(--font);
  transition: border-color .15s, color .15s, background .15s;
  white-space: nowrap;
}
.contributor-remove-btn:hover {
  border-color: var(--danger);
  color: var(--danger);
  background: #fee2e2;
}
[data-theme="dark"] .contributor-remove-btn:hover { background: #450a0a; }

/* ===================== RESPONSIVE ===================== */

@media (max-width: 768px) {
  .home-divider { padding: 0; }

  .chat-sidebar:not(.chat-sidebar--collapsed) { display: none; }

  .room-header { flex-wrap: wrap; gap: 8px; min-height: auto; }
  .room-header-right { flex-wrap: wrap; gap: 4px; }
  .room-title { max-width: 180px; font-size: 15px; }

  .document-view { padding: 28px 24px; }

  .notif-dropdown { width: 280px; right: -30px; }
}

