    30→      )}
    31→      {showReply && (
    32→        <div className="reply-row">
    33→          <input
    34→            className="input input--sm"
    35→            type="text"
    36→            placeholder="Write a reply…"
    37→            value={replyText}
    38→            onChange={e => setReplyText(e.target.value)}
    39→            onKeyDown={e => e.key === 'Enter' && handleReply()}
    40→            autoFocus
    41→          />
    42→          <button
    43→            className="btn btn-sm"
    44→            onClick={handleReply}
    45→            disabled={!replyText.trim()}
