    55→function CommentSection({ contributionId, comments, currentUser, onAddComment }) {
    56→  const [newComment, setNewComment] = useState('');
    57→  const [submitting, setSubmitting] = useState(false);
    58→
    59→  const handleSubmit = async () => {
    60→    if (!newComment.trim() || submitting) return;
    61→    setSubmitting(true);
    62→    await onAddComment(contributionId, newComment.trim());
    63→    setNewComment('');
    64→    setSubmitting(false);
    65→  };
    66→
    67→  // Build tree
    68→  const rootComments = comments.filter(c => !c.parent_id);
    69→  const getChildren = (id) => comments.filter(c => c.parent_id === id);
    70→
    71→  const renderTree = (comment, depth = 0) => (
    72→    <React.Fragment key={comment.id}>
    73→      <Comment
    74→        comment={comment}
    75→        depth={depth}
    76→        onReply={(text, parentId) => onAddComment(contributionId, text, parentId)}
    77→      />
    78→      {getChildren(comment.id).map(child => renderTree(child, depth + 1))}
    79→    </React.Fragment>
    80→  );
    81→
    82→  return (
    83→    <div className="comment-section">
    84→      <div className="comment-list">
    85→        {rootComments.length === 0
    86→          ? <p className="no-comments">No comments yet.</p>
    87→          : rootComments.map(c => renderTree(c))
    88→        }
    89→      </div>
    90→
    91→      {currentUser && (
    92→        <div className="add-comment-row">
    93→          <input
    94→            className="input input--sm"
    95→            type="text"
    96→            placeholder="Add a comment…"
    97→            value={newComment}
    98→            onChange={e => setNewComment(e.target.value)}
    99→            onKeyDown={e => e.key === 'Enter' && handleSubmit()}
   100→          />
   101→          <button
   102→            className="btn btn-sm"
   103→            onClick={handleSubmit}
   104→            disabled={submitting || !newComment.trim()}
   105→          >
   106→            {submitting ? '…' : 'Comment'}
   107→          </button>
   108→        </div>
   109→      )}
   110→    </div>
   111→  );
   112→}
   113→
   114→export default CommentSection;
