    35→app.post('/api/users', (req, res) => {
    36→  const { name, id, color } = req.body;
    37→  if (!name?.trim()) return res.status(400).json({ error: 'Name is required' });
    38→
    39→  const trimmedName = name.trim();
    40→
    41→  if (id) {
    42→    const idx = store.users.findIndex(u => u.id === id);
    43→    if (idx !== -1) {
