    45→      if (color) store.users[idx].color = color;
    46→      save();
    47→      return res.json(store.users[idx]);
    48→    }
    49→  }
    50→
    51→  const user = { id: id || uuidv4(), name: trimmedName, color: color || '#6366f1', created_at: now() };
    52→  store.users.push(user);
    53→  save();
    54→  res.json(user);
    55→});
