     1→/**
     2→ * Simple JSON file-based database — no native compilation needed.
     3→ * All data is kept in memory and written to disk after every mutation.
     4→ */
     5→const fs = require('fs');
     6→const path = require('path');
     7→
     8→const DATA_DIR = path.join(__dirname, 'data');
     9→const DATA_FILE = path.join(DATA_DIR, 'db.json');
    10→
    11→if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
    12→
    13→const EMPTY = {
    14→  users: [],
    15→  rooms: [],
    16→  contributions: [],
    17→  comments: [],
    18→  reactions: [],
    19→  notifications: [],
    20→  chat_messages: [],
    21→  room_members: []
    22→};
    23→
    24→let store;
    25→
    26→try {
    27→  store = fs.existsSync(DATA_FILE)
    28→    ? JSON.parse(fs.readFileSync(DATA_FILE, 'utf8'))
    29→    : { ...EMPTY };
    30→  // Make sure all collections exist (for schema migrations)
    31→  for (const key of Object.keys(EMPTY)) {
    32→    if (!store[key]) store[key] = [];
    33→  }
    34→} catch (e) {
    35→  console.warn('DB load failed, starting fresh:', e.message);
    36→  store = { ...EMPTY };
    37→}
    38→
    39→function save() {
    40→  // Atomic write: write to temp then rename
    41→  const tmp = DATA_FILE + '.tmp';
    42→  fs.writeFileSync(tmp, JSON.stringify(store));
    43→  fs.renameSync(tmp, DATA_FILE);
    44→}
    45→
    46→module.exports = { store, save };
    47→

