     7→function ContributionItem({ contribution, currentUser, isCreator, onDelete, onEdit, onReact, onAddComment, onLoadComments }) {
     8→  const [showComments, setShowComments] = useState(false);
     9→  const [commentsLoaded, setCommentsLoaded] = useState(false);
    10→  const [showPicker, setShowPicker] = useState(false);
    11→  const [editing, setEditing] = useState(false);
    12→  const [editText, setEditText] = useState(contribution.content);
    13→  const [editSaving, setEditSaving] = useState(false);
    14→  const [editError, setEditError] = useState('');
    15→  const pickerRef = useRef(null);
    16→  const editRef = useRef(null);
    17→
    18→  const authorColor = contribution.author_color || getAuthorColor(contribution.author_id);
    19→  const isOwn = contribution.author_id === currentUser?.id;
    20→  const canDelete = isOwn || isCreator;
    21→  const canEdit = isOwn;
    22→
    23→  const handleEditStart = () => {
    24→    setEditText(contribution.content);
    25→    setEditError('');
    26→    setEditing(true);
    27→    setTimeout(() => {
    28→      editRef.current?.focus();
    29→      const len = editRef.current?.value.length;
    30→      editRef.current?.setSelectionRange(len, len);
    31→    }, 0);
    32→  };
    33→
    34→  const handleEditCancel = () => {
    35→    setEditing(false);
    36→    setEditError('');
    37→  };
    38→
    39→  const handleEditSave = async () => {
    40→    if (!editText.trim() || editText.trim() === contribution.content) {
    41→      setEditing(false);
    42→      return;
    43→    }
    44→    setEditSaving(true);
    45→    setEditError('');
    46→    try {
    47→      await onEdit(contribution.id, editText.trim());
    48→      setEditing(false);
    49→    } catch (err) {
    50→      setEditError(err.message);
    51→    }
    52→    setEditSaving(false);
    53→  };
    54→
    55→  // Close picker when clicking outside
    56→  useEffect(() => {
    57→    if (!showPicker) return;
    58→    const handler = (e) => {
    59→      if (!pickerRef.current?.contains(e.target)) setShowPicker(false);
    60→    };
    61→    document.addEventListener('mousedown', handler);
    62→    return () => document.removeEventListener('mousedown', handler);
    63→  }, [showPicker]);
    64→
    65→  // Group reactions: { emoji -> { count, hasMe } }
    66→  const reactionGroups = REACTIONS.reduce((acc, emoji) => {
    67→    const matching = (contribution.reactions || []).filter(r => r.emoji === emoji);
    68→    if (matching.length > 0) {
    69→      acc[emoji] = {
    70→        count: matching.length,
    71→        hasMe: matching.some(r => r.user_id === currentUser?.id)
    72→      };
    73→    }
    74→    return acc;
    75→  }, {});
    76→
    77→  const handleToggleComments = async () => {
    78→    if (!commentsLoaded && contribution.comments === undefined) {
    79→      await onLoadComments(contribution.id);
    80→    }
    81→    setCommentsLoaded(true);
    82→    setShowComments(v => !v);
    83→  };
    84→
    85→  const hasCommentData = commentsLoaded || contribution.comments !== undefined;
    86→  const commentCount = contribution.comments?.length ?? 0;
    87→
    88→  return (
    89→    <article
    90→      className={`contribution ${isOwn ? 'contribution--own' : ''}`}
    91→      style={{ borderLeftColor: authorColor, borderLeftWidth: '4px' }}
    92→    >
    93→      {/* Header */}
    94→      <div className="contribution-header">
    95→        <span
    96→          className="author-avatar"
    97→          style={{ background: authorColor }}
    98→          title={contribution.author_name}
    99→        >
   100→          {contribution.author_name.charAt(0).toUpperCase()}
   101→        </span>
   102→        <span className="author-name">{contribution.author_name}</span>
   103→        <time className="contribution-time" dateTime={new Date(contribution.created_at).toISOString()}>
   104→          {formatTime(contribution.created_at)}
   105→          {contribution.edited_at && <span className="edited-label"> (edited)</span>}
   106→        </time>
   107→        {contribution.status === 'pending' && (
   108→          <span className="contrib-status-badge contrib-status-badge--pending">Pending</span>
   109→        )}
   110→        {contribution.status === 'rejected' && (
   111→          <span className="contrib-status-badge contrib-status-badge--rejected">Rejected</span>
   112→        )}
   113→        {canEdit && !editing && (
   114→          <button className="edit-btn" onClick={handleEditStart} title="Edit contribution">
   115→            ✎
   116→          </button>
   117→        )}
   118→        {canDelete && !editing && (
   119→          <button
   120→            className="delete-btn"
   121→            onClick={() => onDelete(contribution.id)}
   122→            title="Delete contribution"
   123→          >
   124→            ×
   125→          </button>
   126→        )}
   127→      </div>
   128→
   129→      {/* Content */}
   130→      <div className="contribution-body">
   131→        {editing ? (
   132→          <div className="edit-form">
   133→            <textarea
   134→              ref={editRef}
   135→              className="edit-textarea"
   136→              value={editText}
   137→              onChange={e => setEditText(e.target.value)}
   138→              onKeyDown={e => {
   139→                if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) handleEditSave();
   140→                if (e.key === 'Escape') handleEditCancel();
   141→              }}
   142→              rows={Math.max(3, editText.split('\n').length)}
   143→            />
   144→            {editError && <p className="edit-error">{editError}</p>}
   145→            <div className="edit-actions">
   146→              <button className="btn btn-secondary" onClick={handleEditCancel} disabled={editSaving}>
   147→                Cancel
   148→              </button>
   149→              <button className="btn btn-primary" onClick={handleEditSave} disabled={editSaving || !editText.trim()}>
   150→                {editSaving ? 'Saving…' : 'Save'}
   151→              </button>
   152→            </div>
   153→          </div>
   154→        ) : (
   155→          <p>{contribution.content}</p>
   156→        )}
   157→      </div>
   158→
   159→      {/* Footer: reactions + comment toggle */}
   160→      <div className="contribution-footer">
   161→        <div className="reactions-row">
   162→          {Object.entries(reactionGroups).map(([emoji, { count, hasMe }]) => (
   163→            <button
   164→              key={emoji}
   165→              className={`reaction-chip ${hasMe ? 'reaction-chip--active' : ''}`}
   166→              onClick={() => onReact(contribution.id, emoji)}
   167→            >
   168→              {emoji} {count}
   169→            </button>
   170→          ))}
   171→          <div className="reaction-picker-wrap" ref={pickerRef}>
   172→            <button
   173→              className="add-reaction-btn"
   174→              onClick={() => setShowPicker(v => !v)}
   175→              title="Add reaction"
   176→            >
   177→              + 😊
   178→            </button>
   179→            {showPicker && (
   180→              <div className="reaction-picker">
   181→                {REACTIONS.map(emoji => (
   182→                  <button
   183→                    key={emoji}
   184→                    className="reaction-option"
   185→                    onClick={() => { onReact(contribution.id, emoji); setShowPicker(false); }}
   186→                  >
   187→                    {emoji}
   188→                  </button>
   189→                ))}
   190→              </div>
   191→            )}
   192→          </div>
   193→        </div>
   194→
   195→        <button className="comment-toggle" onClick={handleToggleComments}>
   196→          💬 {hasCommentData ? commentCount : '…'} comment{commentCount !== 1 ? 's' : ''}
   197→        </button>
   198→      </div>
   199→
   200→      {/* Comments */}
   201→      {showComments && (
   202→        <CommentSection
   203→          contributionId={contribution.id}
   204→          comments={contribution.comments || []}
   205→          currentUser={currentUser}
   206→          onAddComment={onAddComment}
   207→        />
   208→      )}
   209→    </article>
   210→  );
   211→}
   212→
   213→export default ContributionItem;
