    93→
    94→// ============ ROOM MEMBERS ============
    95→
    96→// Join a room — register/update membership, enforce entry lock
    97→app.post('/api/rooms/:id/join', (req, res) => {
    98→  const { user_id, user_name, user_color } = req.body;
    99→  if (!user_id || !user_name) return res.status(400).json({ error: 'user_id and user_name required' });
   100→
