   290→
   291→// Approve or reject a contribution (room creator only)
   292→app.patch('/api/contributions/:id/status', (req, res) => {
   293→  const { user_id, status } = req.body;
   294→  if (!['approved', 'rejected'].includes(status)) {
   295→    return res.status(400).json({ error: 'status must be "approved" or "rejected"' });
   296→  }
   297→
   298→  const idx = store.contributions.findIndex(c => c.id === req.params.id);
   299→  if (idx === -1) return res.status(404).json({ error: 'Not found' });
   300→
   301→  const contribution = store.contributions[idx];
   302→  const room = store.rooms.find(r => r.id === contribution.room_id);
   303→  if (!room) return res.status(404).json({ error: 'Room not found' });
   304→  if (room.creator_id !== user_id) {
   305→    return res.status(403).json({ error: 'Only the room creator can approve or reject contributions' });
   306→  }
   307→
   308→  contribution.status = status;
   309→
