   311→    // Assign sort_order = max existing approved sort_order + 10
   312→    const approved = store.contributions.filter(c =>
   313→      c.room_id === contribution.room_id && c.status === 'approved' && c.sort_order != null
   314→    );
   315→    const maxOrder = approved.length > 0 ? Math.max(...approved.map(c => c.sort_order)) : 0;
   316→    contribution.sort_order = maxOrder + 10;
   317→  }
   318→
   319→  save();
   320→
   321→  const updated = {
   322→    ...contribution,
   323→    reactions: store.reactions.filter(r => r.contribution_id === contribution.id)
   324→  };
   325→
   326→  io.to(contribution.room_id).emit('contribution_status_changed', updated);
   327→  res.json(updated);
   328→});
   329→
   330→// Reorder approved contributions (room creator only)
   331→app.patch('/api/rooms/:id/reorder', (req, res) => {
   332→  const { user_id, order } = req.body;
   333→  if (!Array.isArray(order)) return res.status(400).json({ error: 'order must be an array of ids' });
   334→
   335→  const room = store.rooms.find(r => r.id === req.params.id);
   336→  if (!room) return res.status(404).json({ error: 'Room not found' });
   337→  if (room.creator_id !== user_id) {
   338→    return res.status(403).json({ error: 'Only the room creator can reorder contributions' });
   339→  }
   340→
   341→  const updates = [];
   342→  order.forEach((id, idx) => {
   343→    const c = store.contributions.find(c => c.id === id && c.room_id === req.params.id);
   344→    if (c) {
   345→      c.sort_order = (idx + 1) * 10;
   346→      updates.push({ id, sort_order: c.sort_order });
   347→    }
   348→  });
   349→
