   490→// ============ SOCKET.IO ============
   491→
   492→// Presence map: socketId → { userId, roomId, userName, userColor }
   493→const presence = {};
   494→
   495→function getOnlineUsers(roomId) {
   496→  return Object.values(presence)
   497→    .filter(p => p.roomId === roomId)
   498→    .map(({ userId, userName, userColor }) => ({ userId, userName, userColor }));
   499→}
   500→
   501→io.on('connection', (socket) => {
   502→  socket.on('join_room', (roomId) => socket.join(roomId));
   503→  socket.on('join_user', (userId) => socket.join(`user_${userId}`));
   504→
   505→  socket.on('user_online', ({ roomId, userId, userName, userColor }) => {
   506→    presence[socket.id] = { userId, roomId, userName, userColor };
   507→    io.to(roomId).emit('presence_update', getOnlineUsers(roomId));
   508→  });
   509→
   510→  socket.on('leave_room', (roomId) => {
   511→    socket.leave(roomId);
   512→    if (presence[socket.id]?.roomId === roomId) {
   513→      delete presence[socket.id];
   514→      io.to(roomId).emit('presence_update', getOnlineUsers(roomId));
   515→    }
   516→  });
   517→
   518→  socket.on('typing', ({ roomId, userName }) => {
   519→    socket.to(roomId).emit('user_typing', { userName });
   520→  });
   521→
   522→  socket.on('disconnect', () => {
   523→    const info = presence[socket.id];
   524→    if (info) {
   525→      delete presence[socket.id];
   526→      io.to(info.roomId).emit('presence_update', getOnlineUsers(info.roomId));
   527→    }
   528→  });
   529→});
